// ==========================================
// 📘 GETTERS & SETTERS
// ==========================================

class User {
    constructor(email, password){
        this.email = email
        this.password = password
    }

    // Getter for email
    get email(){
        return this._email.toUpperCase()
    }

    // Setter for email
    set email(value){
        this._email = value
    }

    // Getter for password
    get password(){
        return `${this._password}hitesh`
    }

    // Setter for password
    set password(value){
        this._password = value
    }
}


// ==========================================
// 📘 Object Creation
// ==========================================

const hitesh = new User(
    "h@hitesh.ai",
    "abc"
)

console.log(hitesh.email)
// Output: H@HITESH.AI

